const source = $node['Build Final HTML Prompt'].json;
const input = $input.first().json;
let html = String(input.html || input.output || input.content || input.improved_html || '').trim();

if (!html) {
  throw new Error('Render Final HTML returned no usable HTML payload.');
}

// Strip any style blocks that are NOT the mandatory #om-top scoped block.
// The #om-top style block is required and must be preserved.
const styleBlockRegex = /<style[^>]*>[\s\S]*?<\/style>/gi;
const styleBlocks = html.match(styleBlockRegex) || [];
for (const block of styleBlocks) {
  if (!block.includes('#om-top')) {
    html = html.replace(block, '');
  }
}

// Strip HTML comments
html = html.replace(/<!--[\s\S]*?-->/g, '');

// Strip script tags (including JSON-LD)
html = html.replace(/<script[\s\S]*?<\/script>/gi, '');

// Normalize em dashes
html = html.replace(/\u2014/g, ', ');

// Validate: must start with <article and end with </article>
if (!/^<article\b/i.test(html)) {
  throw new Error('Final HTML does not start with an <article> element.');
}
if (!html.trimEnd().endsWith('</article>')) {
  throw new Error('Final HTML does not end with </article>.');
}

// Validate: no HTML comments remain
if (/<!--/.test(html)) {
  throw new Error('HTML comments remained after cleanup.');
}

// Validate: no script tags remain
if (/<script\b/i.test(html)) {
  throw new Error('Script tags remained after cleanup.');
}

// Validate: the mandatory #om-top style block is present
if (!/(<style[^>]*>[\s\S]*?#om-top[\s\S]*?<\/style>)/i.test(html)) {
  throw new Error('The mandatory #om-top style block is missing from the output.');
}

return {
  json: {
    ...source,
    cleanedHtml: html
  }
};

